   /**
    * Apply a server-confirmed update.
    */
   applyServerUpdate(postId: string, count: number, serverVersion: number): PostLikeState {
     const current = this.get(postId);
+    // Apply update only if newer or confirming current optimistic state.
+    // This prevents stale server updates (e.g., from WS) from overwriting
+    // a more recent optimistic client state.
+    if (serverVersion > current.version || (serverVersion === current.version && current.optimistic)) {
+      const next: PostLikeState = {
+        postId,
+        count,
+        version: serverVersion,
+        optimistic: false,
+      };
+      this.state.set(postId, next);
+      return next;
+    }
+    // Otherwise, ignore the stale or redundant update.
+    return current;
   }
